<pre><code><$wikify name="cm-raw-preview" text={{!!text}} type={{!!type}} output="html"><$text text=<<cm-raw-preview>>/></$wikify></code></pre>"},"$:/plugins/wikilabs/custom-markup/startup/fix-vocab-type.js":{"title":"$:/plugins/wikilabs/custom-markup/startup/fix-vocab-type.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/startup/fix-vocab-type.js
type: application/javascript
module-type: startup

Patch generateTiddlerFileInfo so tiddlers with type
`text/vnd.tiddlywiki;vocab=...` save as a single .tid file rather than
the body+.meta two-file fallback that exact-match type lookup would
otherwise pick.

The on-disk type field still carries the full parametric value because
the underlying saveTiddlerToFile reads tiddler.fields directly; we only
adjust what generateTiddlerFileInfo sees during its file-format decision.

\*/

"use strict";

exports.name = "cm-fix-vocab-type";
exports.platforms = ["node"];
exports.synchronous = true;

exports.startup = function() {
	if(!$tw.utils || !$tw.utils.generateTiddlerFileInfo) { return; }
	var orig = $tw.utils.generateTiddlerFileInfo;
	$tw.utils.generateTiddlerFileInfo = function(tiddler, options) {
		var type = tiddler && tiddler.fields && tiddler.fields.type;
		if(type && /^text\/vnd\.tiddlywiki\s*;/.test(type)) {
			var clone = new $tw.Tiddler(tiddler, {type: "text/vnd.tiddlywiki"});
			return orig.call(this, clone, options);
		}
		return orig.call(this, tiddler, options);
	};
};
","type":"application/javascript","module-type":"startup"},"$:/plugins/wikilabs/custom-markup/startup/pt-dedupe.js":{"title":"$:/plugins/wikilabs/custom-markup/startup/pt-dedupe.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/startup/pt-dedupe.js
type: application/javascript
module-type: startup

Install the PageTemplate parseTiddler dedupe wrap early — before any
render path can fire `wiki.parseTiddler(PageTemplate)`. TW core's
`getCacheForTiddler` has no in-flight dedupe, so without this wrap the
PageTemplate sub-parser's own `\importcustom` processing (which
spawns sub-parsers for each Pragma-tagged tiddler) can recursively
trigger `parseTiddler(PageTemplate)` again, producing a second full
factory invocation before the outer one stores anything.

Calling `CmRegistry.ensurePageTemplateDedupe(wiki)` is idempotent;
this startup just runs it for `$tw.wiki` once the wiki exists but
before any rendering. The lazy-install path in `CmRegistry`
constructor is still kept as a fallback.

\*/

"use strict";

exports.name = "cm-pt-dedupe";
exports.platforms = ["browser", "node"];
exports.before = ["render"];
exports.synchronous = true;

exports.startup = function() {
	if(!$tw.utils || !$tw.utils.CmRegistry || !$tw.wiki) { return; }
	if(typeof $tw.utils.CmRegistry.ensurePageTemplateDedupe === "function") {
		$tw.utils.CmRegistry.ensurePageTemplateDedupe($tw.wiki);
	}
};
