/* or style specific markers.               */

.wltc-degree { /* ° block paragraph */ }
.wltc-dot { /* . prose-safe block */ }
.wltc-angle { /* » multi-level block */ }
.wltc-single { /* › multi-level block */ }
.wltc-slash { /* /° ... °/ inline */ }
.wltc-corner { /* ❮ ... ❯ inline */ }
.wltc-braille { /* ⠒ ... ⠶ inline */ }

/*------------------------------------------*/
