r":"2","description":"Paragraph block, no symbol. Class chain syntax is `..cls`. Avoids prose collisions like `.NET` or `.com` (allow-symbol off plus strict-class regex)."},"vocab/default/SINGLE":{"title":"vocab/default/SINGLE","tags":"$:/tags/CustomMarkup/Marker [[vocab/default]]","caption":"Single","marker-icon":"$:/plugins/wikilabs/custom-markup/icons/glyphs/single","open":"›","kind":"glyph-level","max-level":"4","mode":"inline","classes":".wltc-single","legacy-kind":"single","order":"3","description":"Paragraph block with multi-level support, distinct default classes from angle."},"vocab/default/SLASH":{"title":"vocab/default/SLASH","tags":"$:/tags/CustomMarkup/Marker [[vocab/default]]","caption":"Slash","marker-icon":"$:/plugins/wikilabs/custom-markup/icons/inline/slash","open":"/°","close":"°/","kind":"inline-pair","classes":".wltc-slash","legacy-kind":"slash","order":"1","description":"Inline wrap; default `<span>`. Easiest inline marker on de/fr keyboards (the ° char is on a dedicated key)."},"vocab/default":{"title":"vocab/default","tags":"$:/tags/CustomMarkup/Vocabulary","caption":"Default","description":"v1 default Custom-Markup vocabulary (4 block markers, 3 inline-pair markers).","version":"0.1.0"},"vocab/legacy-glyphs/APPROX":{"title":"vocab/legacy-glyphs/APPROX","tags":"$:/tags/CustomMarkup/Marker [[vocab/legacy-glyphs]]","caption":"Approx (legacy)","marker-icon":"$:/plugins/wikilabs/custom-markup/icons/glyphs/approx","open":"≈","kind":"glyph-level","max-level":"4","mode":"inline","element":"p","paragraph-marker":"yes","classes":".wltc-approx-legacy","legacy-kind":"approx","description":"Paragraph block with multi-level support (≈ through ≈≈≈≈). Removed from Default in cm-redesign; activate vocab/legacy-glyphs for backward-compat."},"vocab/legacy-glyphs/PILCROW":{"title":"vocab/legacy-glyphs/PILCROW","tags":"$:/tags/CustomMarkup/Marker [[vocab/legacy-glyphs]]","caption":"Pilcrow (legacy)","marker-icon":"$:/plugins/wikilabs/custom-markup/icons/glyphs/pilcrow","open":"¶","kind":"glyph-level","max-level":"4","mode":"inline","element":"p","paragraph-marker":"yes","classes":".wltc-pilcrow-legacy","legacy-kind":"pilcrow","description":"Paragraph block with multi-level support (¶ through ¶¶¶¶). Replaced by `.` in Default; activate vocab/legacy-glyphs for backward-compat with content that still uses `¶`."},"vocab/legacy-glyphs/TICK":{"title":"vocab/legacy-glyphs/TICK","tags":"$:/tags/CustomMarkup/Marker [[vocab/legacy-glyphs]]","caption":"Tick (legacy)","marker-icon":"$:/plugins/wikilabs/custom-markup/icons/glyphs/tick","open":"´","kind":"glyph","mode":"inline","classes":".wltc-tick-legacy","legacy-kind":"tick","description":"Inline wrap; default `<span>`. Single-newline terminated. Removed from Default in cm-redesign; activate vocab/legacy-glyphs for backward-compat with content that still uses `´`."},"vocab/legacy-glyphs":{"title":"vocab/legacy-glyphs","tags":"$:/tags/CustomMarkup/Vocabulary","caption":"Legacy-Glyphs","description":"Backward-compat for ´, ≈, ¶ removed from vocab/default in cm-redesign. Opt in via type=`text/vnd.tiddlywiki;vocab=Default,Legacy-Glyphs` or `\importcustom [tag[vocab/legacy-glyphs]]`.","version":"0.1.0"},"$:/plugins/wikilabs/custom-markup/wl-keyboard.js":{"title":"$:/plugins/wikilabs/custom-markup/wl-keyboard.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wl-keyboard.js
type: application/javascript
module-type: widget-subclass

Keyboard shortcut widget

\*/

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

exports.baseClass = "keyboard";
exports.name = "wl-keyboard";

exports.constructor = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
}

exports.prototype = {};

exports.prototype.handleChangeEvent = function(event) {
	if($tw.keyboardManager.checkKeyDescriptors(event,this.keyInfoArray)) {
		var variables = Object.create(null),
			temp;
		var handled = this.invokeActions(this,event);
		if(this.actions) {
			$tw.utils.each(this.attributes,function(val,key) {
				if (key.substring(0,4) === "usr-") {
					variables[key] = "" + val;
				// } else {
				// 	variables["__" + key + "__"] = "" + val;
				}
			});
			variables = $tw.utils.extend(variables, 
				{ "key": event.key, 
					modifierKey: $tw.keyboardManager.getEventModifierKeyDescriptor(event),
				});
			this.invokeActionString(this.actions,this,event,variables);
		}
		this.dispatchMessage(event);
		if(handled || this.actions || this.message) {
			event.preventDefault();
			event.stopPropagation();
		}
		return true;
	}
	return false;
}

