title: $:/plugins/wikilabs/custom-markup/wl-radio-widget.js
type: application/javascript
module-type: widget-subclass
\*/

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

exports.baseClass = "radio";
exports.name = "wl-radio";

exports.constructor = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
}
exports.prototype = {};

exports.prototype.handleChangeEvent = function(event) {
	var variables = Object.create(null);
	if(this.inputDomNode.checked) {
		this.setValue();
	}
	// Trigger actions. Use variables = {key:value, key:value ...}
	if(this.radioActions) {
		$tw.utils.each(this.attributes,function(val,key) {
			if (key.substring(0,4) === "usr-") {
				variables[key] = "" + val;
			} else {
				variables["__" + key + "__"] = "" + val;
			}
		});
		// "tiddler" and/or "field" parameter may be missing in the widget call. See radio widget .execute() 
		variables = $tw.utils.extend(variables, {"__tiddler__": this.radioTitle,"__field__": this.radioField});
		this.invokeActionString(this.radioActions,this,event,variables);
	}
}
","type":"application/javascript","module-type":"widget-subclass"},"$:/plugins/wikilabs/custom-markup/wikirules/fountain-character.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/fountain-character.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/fountain-character.js
type: application/javascript
module-type: wikirule

Fountain-style automatic character cue detection. A line entirely in
uppercase (letters, digits, space, period, apostrophe, hyphen),
preceded by a blank line (or start of input) and followed immediately
by a non-blank line, renders as a Fountain character cue. An optional
same-line parenthetical extension (`MOM (O. S.)`, `HANS (on the
radio)`) is included in the rendered cue with its original case
preserved.

Character names must contain at least one alphabetical character per
the Fountain spec — the leading `[A-Z]` requirement satisfies this.

Dual dialogue: a trailing caret `^` on the cue line (any number of
spaces before it, ignored) marks the cue as the second speaker in a
simultaneous-dialogue pair. The caret is stripped from the rendered
cue and the wrapping div picks up `wltc-fountain-cue-block-dual` so
CSS can lay the pair out side-by-side.

The rule consumes both the cue line AND the following dialogue
paragraph (up to the next blank line) and wraps them in a single
`<div class="wltc-fountain-cue-block">`. Wrapping is required so dual
dialogue can be styled as adjacent columns; without a wrapper, the
flat sequence of cue/dialogue paragraphs can't be reliably grouped
via CSS sibling selectors.

Fires only when an activated vocabulary opts in via
`auto-character: yes` (e.g. vocab/fountain).

Disambiguation from scene headings: Fountain word markers in the same
vocab should set `trailing-blank: yes` on their marker tiddlers so that
`INT. KITCHEN\nJane enters.` (no trailing blank) falls through to
auto-character, while `INT. KITCHEN\n\nJane enters.` (with trailing
blank) fires as a scene heading.

\*/

"use strict";

exports.name = "fountain-character";
exports.types = {block: true};

// (?<=^|\n\n)  preceded by start-of-input or a blank line.
// ([ \t]*)     optional indent (captured but ignored on render).
// (            cue:
//   [A-Z]                          must start with an uppercase letter
//   [A-Z0-9 .'\-]*?                uppercase/digit/punctuation, lazy
//   (?:\s*\([^)\n]*\))?            optional same-line parenthetical
// )
// [ \t]*       trailing whitespace allowed before the dual marker
// (\^)?        optional caret = dual dialogue
// [ \t]*\n     trailing whitespace + cue-line newline
// (?=[ \t]*\S) next line is non-blank (allows indented dialogue)
var CHAR_RE = /(?<=^|\n\n)([ \t]*)([A-Z][A-Z0-9 .'\-]*?(?:\s*\([^)\n]*\))?)[ \t]*(\^)?[ \t]*\n(?=[ \t]*\S)/g;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = CHAR_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("auto-character")) {
		return undefined;
	}
	var regex = new RegExp(CHAR_RE.source, "g");
	regex.lastIndex = startPos;
	var match = regex.exec(this.parser.source);
	if(!match) { return undefined; }
	this.match = match;
	return match.index;
};

exports.parse = function() {
	var match = this.match;
	var cueName = match[2];
	var isDual = !!match[3];

	// Advance past the cue line; parser.pos now points at the dialogue.
	this.parser.pos = match.index + match[0].length;

	// Consume the dialogue paragraph: inline content up to the next blank
	// line (or end of input). preserve-newlines (vocab-active) converts
	// intra-paragraph `\n` to `<br>`, so multi-line dialogue and
	// parentheticals on their own lines render with line breaks.
	var dialogueChildren = this.parser.parseInlineRun(/(\r?\n\r?\n)/mg, {eatTerminator: true});

	var classes = "wltc-fountain-cue-block";
	if(isDual) { classes += " wltc-fountain-cue-block-dual"; }

	return [{
		type: "element",
		tag: "div",
		attributes: {
			"class": {type: "string", value: classes}
		},
		children: [
			{
				type: "element",
				tag: "p",
				attributes: {
					"class": {type: "string", value: "wltc-fountain-character"}
				},
				children: [{type: "text", text: cueName}]
			},
			{
				type: "element",
				tag: "p",
				attributes: {
					"class": {type: "string", value: "wltc-fountain-dialogue"}
				},
				children: dialogueChildren
			}
		]
	}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/fountain-page-break.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/fountain-page-break.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/fountain-page-break.js
type: application/javascript
module-type: wikirule

Fountain page break: a line of three or more `=` characters, preceded
by a blank line (or start of input) and followed by a blank line (or
end of input). Emits `<div class="wltc-fountain-page-break"></div>`;
print CSS turns it into a `page-break-after: always` so PDF / paper
output respects the author's hard breaks.

The title-page terminator is also `===`, but the front-matter rule
fires first (only at `parser.pos === 0`) and consumes its own
separator. By the time this rule sees source after position 0, any
title-page `===` is already gone.

Gated on `page-break: yes` on an active vocab (e.g. vocab/fountain).

\*/

"use strict";

// Blank-before, indent (captured but ignored), 3+ `=`, trailing
// whitespace, newline, then blank-after (a second newline or end of
// input). Same shape as fountain-transition's auto rule.
var PB_RE = /(?<=^|\n\n)([ \t]*)={3,}[ \t]*\n(?=\n|(?![\s\S]))/g;

exports.name = "fountain-page-break";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = PB_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("page-break")) {
		return undefined;
	}
	var regex = new RegExp(PB_RE.source, "g");
	regex.lastIndex = startPos;
	var match = regex.exec(this.parser.source);
	if(!match) { return undefined; }
	this.match = match;
	return match.index;
};

exports.parse = function() {
	this.parser.pos = this.match.index + this.match[0].length;
	return [{
		type: "element",
		tag: "div",
		attributes: {
			"class": {type: "string", value: "wltc-fountain-page-break"}
		}
	}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/fountain-transition.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/fountain-transition.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/fountain-transition.js
type: application/javascript
module-type: wikirule

Fountain transitions outside the named-keyword marker set:

1. ''Auto-detected.'' An uppercase line ending with `TO:`, preceded by
   a blank line and followed by a blank line (or end of input). Covers
   generic transitions like `JUMP TO:` or `ROLL TO:`. Gated on
   `auto-transition: yes` on an active vocab.

2. ''Forced.'' A line starting with `>` (no trailing `<`, which would
   make it a centered line). Any text — uppercase or mixed case —
   becomes the transition body. Gated on `forced-transition: yes` on an
   active vocab. The `>` and any leading space after it are stripped.

If a candidate auto line matches the open of an active word marker
(e.g. `CUT TO:`), this rule yields so the specific marker fires
instead.

\*/

"use strict";

// Auto-detected: blank-before, uppercase ... TO:, blank-after.
var AUTO_RE = /(?<=^|\n\n)([ \t]*)([A-Z][A-Z0-9 .'\-]*TO:)[ \t]*\n(?=\n|(?![\s\S]))/g;

// Forced: blank-before, `>` then optional space then a non-empty body
// whose last non-whitespace char is not `<` (which would mean centered).
// Trailing whitespace + newline.
var FORCED_RE = /(?<=^|\n\n)([ \t]*)>[ \t]*(\S[^\n]*?)(?<!<)[ \t]*\n/g;

exports.name = "fountain-transition";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	// matchRegExp is informational; we re-derive per-call below.
	this.matchRegExp = AUTO_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	var registry = this.parser.cmRegistry;
	if(!registry) { return undefined; }
	var wantAuto = registry.hasVocabFlag("auto-transition");
	var wantForced = registry.hasVocabFlag("forced-transition");
	if(!wantAuto && !wantForced) { return undefined; }

	var autoMatch = wantAuto ? nextAutoMatch(this.parser.source, startPos, registry) : null;
	var forcedMatch = wantForced ? nextForcedMatch(this.parser.source, startPos) : null;

	var pick = pickEarlier(autoMatch, forcedMatch);
	if(!pick) { return undefined; }
	this.match = pick.match;
	this.mode = pick.mode;
	return pick.match.index;
};

exports.parse = function() {
	var match = this.match;
	var label = this.mode === "forced" ? match[2] : match[2];
	this.parser.pos = match.index + match[0].length;
	return [{
		type: "element",
		tag: "p",
		attributes: {
			"class": {type: "string", value: "wltc-fountain-transition"}
		},
		children: [{type: "text", text: label}]
	}];
};

function nextAutoMatch(source, startPos, registry) {
	var regex = new RegExp(AUTO_RE.source, "g");
	regex.lastIndex = startPos;
	while(true) {
		var m = regex.exec(source);
		if(!m) { return null; }
		if(specificMarkerWins(m[2], registry)) {
			regex.lastIndex = m.index + 1;
			continue;
		}
		return m;
	}
}

function nextForcedMatch(source, startPos) {
	var regex = new RegExp(FORCED_RE.source, "g");
	regex.lastIndex = startPos;
	var m = regex.exec(source);
	return m || null;
}

function pickEarlier(a, b) {
	if(a && b) { return a.index <= b.index ? {match: a, mode: "auto"} : {match: b, mode: "forced"}; }
	if(a) { return {match: a, mode: "auto"}; }
	if(b) { return {match: b, mode: "forced"}; }
	return null;
}

// Returns true if the candidate line text matches an active word
// marker's open literal (case-insensitive when the marker opts in).
// When true the marker engine will fire its specific marker and we
// should yield.
function specificMarkerWins(lineText, registry) {
	var markers = registry.list();
	for(var i = 0; i < markers.length; i++) {
		var m = markers[i];
		if(m.kind !== "word") { continue; }
		if(!registry.isActive(m.open)) { continue; }
		if(m.caseInsensitive) {
			var head = lineText.substring(0, m.open.length);
			if(head.toLowerCase() === m.open.toLowerCase()) { return true; }
		} else if(lineText.indexOf(m.open) === 0) {
			return true;
		}
	}
	return false;
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/backslash-escapes.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/backslash-escapes.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/backslash-escapes.js
type: application/javascript
module-type: wikirule

CommonMark backslash escapes: `\X` where X is one of the 30 ASCII
punctuation characters renders as the literal X (the leading backslash
is consumed). Lets authors write `\*literal asterisks\*` without
triggering the italic marker, `` \` `` without a code span, `\[` without
a linked-pair, etc. Backslash followed by anything other than ASCII
punctuation is left alone (CommonMark spec: `\A` stays `\A`).

Fires when any active vocab opts in via `backslash-escapes: yes`.
vocab/markdown does. The rule only fires at inline positions, so source
captured raw — fenced code blocks, code spans (`body-raw: yes`),
linked-pair `body-attribute` strings — is unaffected: backslashes inside
those bodies stay literal.

\*/

"use strict";

exports.name = "markdown-backslash-escapes";
exports.types = {inline: true};

// CommonMark Section 6.1 escapable characters:
//   ! " # $ % & ' ( ) * + , - . / : ; < = > ? @ [ \ ] ^ _ ` { | } ~
var ESCAPE_RE = /\\([!"#$%&'()*+,\-./:;<=>?@\[\\\]^_`{|}~])/g;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = ESCAPE_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("backslash-escapes")) {
		return undefined;
	}
	this.matchRegExp.lastIndex = startPos;
	this.match = this.matchRegExp.exec(this.parser.source);
	return this.match ? this.match.index : undefined;
};

exports.parse = function() {
	this.parser.pos = this.match.index + this.match[0].length;
	return [{type: "text", text: this.match[1]}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/front-matter.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/front-matter.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/front-matter.js
type: application/javascript
module-type: wikirule

YAML front-matter block. Fires only at parser.pos === 0 and only when
an activated vocab meta tiddler declares `front-matter: yes`. Reads
lines from the top of the source until a blank line or a `===` (or
longer) separator and hands the captured text to the YAML library;
the resulting object becomes one row per top-level key in the rendered
`<div class="wltc-front-matter">`.

The capture phase accepts both `Key: Value` lines and continuation
lines that begin with whitespace, so YAML's spec-compliant multi-line
values (Fountain title-page `Notes:\n\tline\n\tline`) survive into the
parser. The first line must still look like a top-level `Key:` so we
don't grab arbitrary prose.

Rendering keeps the previous structure: each top-level pair produces a
`<div class="wltc-front-matter-row" data-key="<Key>">` with a hidden
key span and a value span. Scalar values render directly; arrays
render as comma-joined strings; nested maps fall back to a JSON-ish
inline form (the simple title-page case rarely needs more).

\*/

"use strict";

var yaml = require("$:/plugins/wikilabs/custom-markup/yaml.js");

// Match a top-level `Key:` line. Key must start with an uppercase
// letter so we don't catch random `word: thing` mid-sentence; allow
// word chars, hyphens, and embedded single spaces so multi-word keys
// like `Draft date:` survive (common in Fountain title pages). The
// trailing assertion requires whitespace or end-of-line after the
// colon to avoid matching URLs (`https:` ...).
var KEY_LINE_RE = /^[A-Z][\w-]*(?:[ ][\w-]+)*:(?:[ \t]|$)/;
var SEPARATOR_RE = /^={3,}[ \t]*$/;

exports.name = "frontmatter";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(startPos !== 0) { return undefined; }
	if(!this.parser.cmRegistry.hasVocabFlag("front-matter")) { return undefined; }
	var firstLine = readLine(this.parser.source, 0);
	if(!KEY_LINE_RE.test(firstLine.text)) { return undefined; }
	this.match = [firstLine.text];
	return 0;
};

exports.parse = function() {
	var source = this.parser.source;
	var pos = 0;
	var captured = [];
	while(pos < source.length) {
		var line = readLine(source, pos);
		if(line.text === "" || /^\s*$/.test(line.text)) {
			pos = line.nextPos;
			break;
		}
		if(SEPARATOR_RE.test(line.text)) {
			pos = line.nextPos;
			break;
		}
		// Accept top-level Key: lines, or continuation lines that begin
		// with whitespace (YAML's spec for multi-line scalar values).
		// Anything else ends the block without consuming the offending
		// line, so the next rule can handle it.
		if(!KEY_LINE_RE.test(line.text) && !/^[ \t]/.test(line.text)) {
			break;
		}
		captured.push(line.text);
		pos = line.nextPos;
	}
	this.parser.pos = pos;
	if(captured.length === 0) { return []; }
	var parsed;
	try {
		parsed = yaml.load(captured.join("\n"));
	} catch(e) {
		// If YAML parsing fails, treat the block as not-front-matter:
		// rewind the parser to before the block so the lines render via
		// regular rules.
		this.parser.pos = 0;
		return [];
	}
	if(!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
		this.parser.pos = 0;
		return [];
	}
	var keys = Object.keys(parsed);
	if(keys.length === 0) { return []; }
	var children = keys.map(function(key) {
		var value = parsed[key];
		return {
			type: "element", tag: "div",
			attributes: {
				"class": {type: "string", value: "wltc-front-matter-row"},
				"data-key": {type: "string", value: key}
			},
			children: [
				{
					type: "element", tag: "span",
					attributes: {"class": {type: "string", value: "wltc-front-matter-key"}},
					children: [{type: "text", text: key + ": "}]
				},
				{
					type: "element", tag: "span",
					attributes: {"class": {type: "string", value: "wltc-front-matter-value"}},
					children: [{type: "text", text: formatValue(value)}]
				}
			]
		};
	});
	return [{
		type: "element", tag: "div",
		attributes: {"class": {type: "string", value: "wltc-front-matter"}},
		children: children
	}];
};

// Coerce a parsed YAML value into a single display string. The common
// title-page cases are strings; arrays show as comma-joined; anything
// else (object, null) falls back to JSON so the user at least sees the
// data rather than `[object Object]`.
function formatValue(value) {
	if(value === null || value === undefined) { return ""; }
	if(typeof value === "string") { return value; }
	if(typeof value === "number" || typeof value === "boolean") {
		return String(value);
	}
	if(Array.isArray(value)) {
		return value.map(formatValue).join(", ");
	}
	try {
		return JSON.stringify(value);
	} catch(e) {
		return String(value);
	}
}

function readLine(source, pos) {
	var nlIdx = source.indexOf("\n", pos);
	if(nlIdx === -1) {
		return {text: source.substring(pos), nextPos: source.length};
	}
	var text = source.substring(pos, nlIdx);
	if(text.charAt(text.length - 1) === "\r") {
		text = text.substring(0, text.length - 1);
	}
	return {text: text, nextPos: nlIdx + 1};
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js
type: application/javascript
module-type: wikirule

Preserve intra-paragraph newlines: every single `\n` (or `\r\n`) emits
a `<br>`. Blank-line paragraph breaks already work via TW's block
parser, which terminates the inline run at `\n\n` before this rule can
see the second newline — so this rule only fires on single newlines
inside a paragraph, never on the boundary between paragraphs.

Fires when any activated vocab opts in via `preserve-newlines: yes`
(e.g. vocab/markdown, vocab/fountain).

\*/

"use strict";

exports.name = "markdown-newline";
exports.types = {inline: true};

// Kept for informational `matchRegExp` (some TW internals inspect it).
// The hot scan path below uses indexOf instead — `\n` is the most common
// character in multi-paragraph content and a regex allocation per call
// is wasteful for a fixed two-char pattern.
var NL_RE = /\r?\n/g;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = NL_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("preserve-newlines")) {
		return undefined;
	}
	var source = this.parser.source;
	var nlIdx = source.indexOf("\n", startPos);
	if(nlIdx === -1) { return undefined; }
	// Mirror `\r?\n`: include a preceding `\r` in the match when present
	// AND within the current search window.
	var matchIdx = (nlIdx > startPos && source.charAt(nlIdx - 1) === "\r")
		? nlIdx - 1
		: nlIdx;
	this.matchEnd = nlIdx + 1;
	return matchIdx;
};

exports.parse = function() {
	this.parser.pos = this.matchEnd;
	return [{type: "element", tag: "br"}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/markdown-ref-def.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/markdown-ref-def.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-flavour/markdown-ref-def.js
type: application/javascript
module-type: wikirule

CommonMark reference-link definitions: `[label]: target "optional title"`
at line start (up to 3 leading spaces). The target may be wrapped in
`<...>` to allow whitespace. Captures into `parser.cmRegistry.linkRefs`
so the `vocab/markdown/LINK-REF` marker can resolve `[text][label]` and
similar reference shapes at parse time. Defs must appear BEFORE their
usages in the source (single-pass; no pre-scan).

Emits nothing — ref-defs are invisible per CommonMark. Fires when any
active vocab opts in via `reference-links: yes` (vocab/markdown by
default).

\*/

"use strict";

exports.name = "markdown-ref-def";
exports.types = {block: true};

// 0-3 spaces of indent, then `[label]:`, optional whitespace, then the
// target either as `<wrapped>` (allows spaces inside) or as a bare
// non-whitespace run, then optional `"title"` / `'title'` / `(title)`,
// then optional trailing whitespace and EOL.
var REF_DEF_RE = /^[ ]{0,3}\[((?:\\[\\\[\]]|[^\]\\\r\n])+)\]:[ \t]*(?:<([^>\r\n]*)>|([^\s<>][^\s]*))(?:[ \t]+(?:"([^"\r\n]*)"|'([^'\r\n]*)'|\(([^)\r\n]*)\)))?[ \t]*(?:\r?\n|$)/mg;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = REF_DEF_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("reference-links")) {
		return undefined;
	}
	this.matchRegExp.lastIndex = startPos;
	this.match = this.matchRegExp.exec(this.parser.source);
	return this.match ? this.match.index : undefined;
};

exports.parse = function() {
	this.parser.pos = this.matchRegExp.lastIndex;
	var label = $tw.utils.CmRegistry.normalizeRefLabel(this.match[1]);
	// Target is whichever capture group matched: `<wrapped>` or bare.
	var target = this.match[2] !== undefined ? this.match[2] : this.match[3];
	// Title is whichever of the three quote styles matched.
	var title = this.match[4] || this.match[5] || this.match[6] || "";

	var registry = this.parser.cmRegistry;
	if(!registry.linkRefs) { registry.linkRefs = Object.create(null); }
	// CommonMark: first definition wins (later same-label defs are ignored).
	if(!registry.linkRefs[label]) {
		registry.linkRefs[label] = {target: target, title: title};
	}

	// Ref-defs are invisible per CommonMark spec.
	return [];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js
type: application/javascript
module-type: wikirule

Markdown-style table block rule. Fires only when an activated vocab opts
in via `tables: yes` (e.g. vocab/markdown).

Recognises pipe-syntax tables with a required separator row:

```
| Header 1 | Header 2 | Header 3 |
|----------|:--------:|---------:|
| left     | centre   | right    |
| cell     | cell     | cell     |
```

Alignment derives from the separator row's colons: `:-` left,
`:-:` centre, `-:` right, plain `-` defaults to left. A blank line or any
line not starting with `|` ends the table. Cells are emitted as plain
text in v1; inline emphasis inside cells is a future enhancement.

\*/

"use strict";

exports.name = "markdown-table";
exports.types = {block: true};

// Match a header row immediately followed by a separator row. The
// separator constraint is what distinguishes a real markdown table from
// any other line that happens to contain pipes.
var TABLE_RE = /^[ \t]*\|[^\r\n]+\|[ \t]*\r?\n[ \t]*\|(?:[ \t]*:?-+:?[ \t]*\|)+[ \t]*(?:\r?\n|$)/mg;
var ROW_RE = /^[ \t]*\|([^\r\n]*?)\|[ \t]*(\r?\n|$)/mg;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = TABLE_RE;
	$tw.utils.CmRegistry.ensureRegistry(parser);
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.hasVocabFlag("tables")) {
		return undefined;
	}
	var regex = new RegExp(TABLE_RE.source, "mg");
	regex.lastIndex = startPos;
	var match = regex.exec(this.parser.source);
	if(!match) { return undefined; }
	this.match = match;
	return match.index;
};

exports.parse = function() {
	var parser = this.parser;
	var headerCells = readInlineRow(parser);
	if(!headerCells) { return [textFallback(parser)]; }
	var separatorText = readPlainRow(parser);
	if(separatorText === null) { return [textFallback(parser)]; }
	var alignments = separatorText.split("|").map(function(c) {
		return c.replace(/^[ \t]+|[ \t]+$/g, "");
	}).map(parseAlignment);

	var dataRows = [];
	while(parser.pos < parser.source.length) {
		var saved = parser.pos;
		var cells = readInlineRow(parser);
		if(!cells) { parser.pos = saved; break; }
		dataRows.push(cells);
	}

	return [buildTable(headerCells, dataRows, alignments)];
};

// Read one row as plain text (used for the separator). Returns the inner
// content (between first and last `|`), advances parser.pos past the
// trailing newline. Null if not a pipe row.
function readPlainRow(parser) {
	var regex = new RegExp(ROW_RE.source, "mg");
	regex.lastIndex = parser.pos;
	var match = regex.exec(parser.source);
	if(!match || match.index !== parser.pos) { return null; }
	parser.pos = match.index + match[0].length;
	return match[1];
}

// Read one row with each cell parsed as an inline run, so emphasis
// markers inside cells (e.g. `*italic*`, `` `code` ``) fire. Advances
// parser.pos past the trailing newline. Null if not a pipe row.
function readInlineRow(parser) {
	var src = parser.source;
	var startPos = parser.pos;
	// Find row extent: from current pos to end-of-line.
	var nlIdx = src.indexOf("\n", startPos);
	if(nlIdx === -1) { nlIdx = src.length; }
	// Trim trailing whitespace (including any \r before \n).
	var rowEnd = nlIdx;
	while(rowEnd > startPos && /[ \t\r]/.test(src.charAt(rowEnd - 1))) { rowEnd--; }
	// Row must start (after optional indent) and end with `|`.
	var probe = startPos;
	while(probe < rowEnd && /[ \t]/.test(src.charAt(probe))) { probe++; }
	if(src.charAt(probe) !== "|" || src.charAt(rowEnd - 1) !== "|") { return null; }

	parser.pos = probe + 1; // past the opening `|`
	var cells = [];
	while(parser.pos < rowEnd - 1) {
		// Trim leading whitespace inside the cell.
		while(parser.pos < rowEnd - 1 && /[ \t]/.test(src.charAt(parser.pos))) { parser.pos++; }
		// Parse inline content until the next `|` (or end of row).
		var cellTerm = /\|/g;
		var children = parser.parseInlineRun(cellTerm);
		trimTrailingWhitespace(children);
		cells.push(children);
		// Step past the `|` separator.
		if(parser.pos < rowEnd && src.charAt(parser.pos) === "|") { parser.pos++; }
		else { break; }
	}
	// Advance past the closing `|` (if not already) and the newline.
	parser.pos = nlIdx < src.length ? nlIdx + 1 : nlIdx;
	return cells;
}

function trimTrailingWhitespace(children) {
	if(children.length === 0) { return; }
	var last = children[children.length - 1];
	if(last && last.type === "text" && typeof last.text === "string") {
		last.text = last.text.replace(/[ \t]+$/, "");
		if(last.text === "") { children.pop(); }
	}
}

// Parse one separator cell like "---", ":---", "---:", ":---:" into
// "left" / "centre" / "right". Anything else defaults to "left".
function parseAlignment(cell) {
	var trimmed = cell.replace(/^[ \t]+|[ \t]+$/g, "");
	var leadsColon = trimmed.charAt(0) === ":";
	var trailsColon = trimmed.charAt(trimmed.length - 1) === ":";
	if(leadsColon && trailsColon) { return "center"; }
	if(trailsColon) { return "right"; }
	return "left";
}

function buildTable(headerCells, dataRows, alignments) {
	function cellNode(tag, children, align) {
		var attrs = {};
		if(align && align !== "left") {
			attrs.style = {type: "string", value: "text-align:" + align};
		}
		return {
			type: "element",
			tag: tag,
			attributes: attrs,
			children: children
		};
	}
	function rowNode(cells, tag) {
		return {
			type: "element",
			tag: "tr",
			children: cells.map(function(c, i) {
				return cellNode(tag, c, alignments[i] || "left");
			})
		};
	}
	return {
		type: "element",
		tag: "table",
		children: [
			{
				type: "element",
				tag: "thead",
				children: [rowNode(headerCells, "th")]
			},
			{
				type: "element",
				tag: "tbody",
				children: dataRows.map(function(r) { return rowNode(r, "td"); })
			}
		]
	};
}

// Last-resort fallback used when findNextMatch matched a position but
// parse() couldn't read a valid header/separator pair (shouldn't happen
// with our tight regex, but defends against future regex drift).
function textFallback(parser) {
	var nlIdx = parser.source.indexOf("\n", parser.pos);
	if(nlIdx === -1) { nlIdx = parser.source.length; }
	var text = parser.source.substring(parser.pos, nlIdx);
	parser.pos = nlIdx + 1;
	return {type: "text", text: text};
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/marker-block.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/marker-block.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/marker-block.js
type: application/javascript
module-type: wikirule

Block-level Custom-Markup parse rule. One rule for all block-invokable
markers (glyph, glyph-level, word). Reads from parser.cmRegistry.

\*/

"use strict";

exports.name = "cmblock";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	// Builds the registry on first wikirule init() for this parser: loads
	// all markers (so the combined regex is comprehensive — vocab scoping is
	// enforced by the active-set check in parse() below), pulls bridged
	// symbols from PageTemplate's `\importcustom`-loaded pragmas, activates
	// vocabs from the parser type, and schedules the deferred core-rule
	// exclusions (see registry.applyAmendRules for why init() is too early
	// to amend rules directly).
	var registry = $tw.utils.CmRegistry.ensureRegistry(parser);
	this.matchRegExp = registry.getBlockRegex() || /(?!)/g;
};

// Override the default findNextMatch so that AFTER pragmas have parsed
// (so `\importcustom` has had its chance to activate vocabs), we skip
// over inactive marker positions instead of claiming them. Without this
// filter, an inactive marker whose open literal collides with a TW core
// rule (Vocab/Fountain's `#` SECTION vs core `list`, etc.) would silently
// eat the position via the text-fallback in parse(), suppressing the
// core rule for any tiddler in the wiki — even tiddlers that don't
// activate the offending vocab.
//
// Before pragmas: behave like the default (accept any marker match) so
// the rule survives TW's `instantiateRules` pruning and remains
// available for pragma-activated vocabs to use.
exports.findNextMatch = function(startPos) {
	var source = this.parser.source;
	var regex = this.matchRegExp;
	regex.lastIndex = startPos;
	var match;
	while((match = regex.exec(source)) !== null) {
		if(this.parser._cmPragmasDone) {
			var marker = identifyMarker(match[0], this.parser.cmRegistry);
			if(!marker || !this.parser.cmRegistry.isActive(marker.open)) {
				regex.lastIndex = match.index + 1;
				continue;
			}
		}
		this.match = match;
		return match.index;
	}
	this.match = null;
	return undefined;
};

exports.parse = function() {
	var registry = this.parser.cmRegistry;
	var matchText = this.match[0];
	var marker = identifyMarker(matchText, registry);
	if(!marker) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [];
	}
	// Vocabulary scoping: emit matched text as plain text if the marker's
	// open isn't in any active vocabulary for this parser.
	if(!registry.isActive(marker.open)) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [{type: "text", text: matchText}];
	}
	// List-item markers consume the whole list in one parse() call:
	// consecutive items collapse into a single container element, deeper
	// indent nests under the previous item, container switch starts a
	// sibling list. Body of each item parses as an inline run.
	if(marker.kind === "list-item") {
		return parseListItems(this.parser, this.match, this.matchRegExp);
	}
	// Fenced markers consume the whole block in one parse() call: the
	// open line gives the fence-run length and info string, the body is
	// captured raw until a matching close fence (same char, run length
	// >= open length, on its own line), implicit close at EOF.
	if(marker.kind === "fenced") {
		return parseFenced(this.parser, marker, this.match);
	}
	// Hr markers fire on a thematic-break line: open + optional more of
	// the same char + optional whitespace + EOL. No body, no symbol, no
	// quoted args — just emit the configured element with classes.
	if(marker.kind === "hr") {
		return parseHr(this.parser, marker, this.matchRegExp);
	}
	var textStart = this.match.index;
	var parsed = parseMatchTail(matchText, marker);
	this.parser.pos = this.matchRegExp.lastIndex;
	this.parser.skipWhitespace({treatNewlinesAsNonWhitespace: true});
	var contentStart = this.parser.pos;
	var config = resolveConfig(marker, parsed.symbol, parsed.classes, parsed.level);
	config.quotedArgs = parsed.quotedArgs;
	var children = parseBody(this.parser, config);
	// Marker opts into keeping its open literal visible as body content
	// (Fountain transitions: `CUT TO:`, `FADE IN:`, ... where the keyword
	// IS the content). Add a trailing space when body has content so the
	// open literal and body don't run together (`INT. KITCHEN`, not
	// `INT.KITCHEN`); skipWhitespace eats the source-side separator before
	// body parsing begins, so we re-introduce it on the rendered side.
	if(marker.emitOpen === "yes") {
		children.unshift({type: "text", text: children.length > 0 ? marker.open + " " : marker.open});
	}
	var textEnd = this.parser.pos;
	var nodes = [];
	// `\debugmarker` pragma overrides the marker's static `debug` field for
	// this tiddler. `debugMarkerAllOff` is the wiki-wide off switch
	// (`\debugmarker no`); per-marker entries in `debugMarkerOverrides`
	// (including `=no`) win over the field.
	var effectiveDebug = resolveDebugMode(this.parser, marker.open, config.debug);
	if(effectiveDebug && effectiveDebug !== "no") {
		// Strip the trailing terminator (newline or blank-line) that
		// eatTerminator consumed, so the debug `text` codeblock matches
		// v0.x's clean per-marker source slice.
		var textOuter = this.parser.source.slice(textStart, textEnd).replace(/(?:\r?\n)+$/, "");
		nodes = nodes.concat(buildDebugNodes(effectiveDebug, config.debugString || "", textOuter));
	}
	if(!isDebugRenderSuppressed(effectiveDebug)) {
		nodes.push(buildNode(config, children, this.parser.source, contentStart, textEnd));
	}
	return nodes;
};

function resolveDebugMode(parser, open, fieldDebug) {
	if(parser.debugMarkerAllOff) { return "no"; }
	var overrides = parser.debugMarkerOverrides;
	if(overrides && Object.prototype.hasOwnProperty.call(overrides, open)) {
		return overrides[open];
	}
	return fieldDebug;
}

// `_debug` modes from v0.x (glyph-text.js / glyph-inline.js):
//   pragma (default), pragmaOnly, text, textOnly, both, no.
// `*Only` variants suppress the normal render. `both` shows both code blocks.
function buildDebugNodes(debug, debugString, textOuter) {
	var nodes = [];
	switch(debug) {
		case "both":
			nodes.push(codeblockNode(debugString));
			nodes.push(codeblockNode(textOuter));
			break;
		case "text":
		case "textOnly":
			nodes.push(codeblockNode(textOuter));
			break;
		case "pragmaOnly":
		case "pragma":
		default:
			nodes.push(codeblockNode(debugString));
	}
	return nodes;
}

function isDebugRenderSuppressed(debug) {
	return debug === "textOnly" || debug === "pragmaOnly";
}

function codeblockNode(text) {
	return {
		type: "codeblock",
		attributes: {code: {type: "string", value: text || ""}}
	};
}

function identifyMarker(matchText, registry) {
	var markers = registry.list();
	markers.sort(function(a, b) {
		// Word ahead of non-word; longest open first within each
		if(a.kind === "word" && b.kind !== "word") { return -1; }
		if(a.kind !== "word" && b.kind === "word") { return 1; }
		var aLen = a.kind === "list-item" ? (a.openPattern || a.open).length : a.open.length;
		var bLen = b.kind === "list-item" ? (b.openPattern || b.open).length : b.open.length;
		return bLen - aLen;
	});
	// list-item matches start with optional indent; strip it before testing
	// the bullet so e.g. "  - " resolves to the dash marker.
	var trimmed = matchText.replace(/^[ \t]+/, "");
	for(var i = 0; i < markers.length; i++) {
		var m = markers[i];
		if(m.kind === "list-item") {
			if(m.openPattern) {
				if(new RegExp("^(?:" + m.openPattern + ")").test(trimmed)) {
					return m;
				}
			} else if(trimmed.indexOf(m.open) === 0) {
				return m;
			}
		} else if(m.caseInsensitive) {
			// Case-insensitive word markers (e.g. Fountain `INT.` matching
			// `int.` / `Int.`). Compare lowercased so the marker resolves
			// regardless of source case.
			var head = matchText.substring(0, m.open.length);
			if(head.toLowerCase() === m.open.toLowerCase()) {
				return m;
			}
		} else if(matchText.indexOf(m.open) === 0) {
			return m;
		}
	}
	return null;
}

// Consume a run of list-item matches into a nested tree of container
// elements. Each item's body is parsed as an inline run terminated by
// the next newline. Indent (after tab-expansion to indent-unit spaces)
// drives nesting level; container change at the same level starts a
// sibling list.
function parseListItems(parser, firstMatch, blockRegExp) {
	var registry = parser.cmRegistry;
	var roots = [];
	var stack = []; // [{listNode, container, level}]
	var sharedRe = new RegExp(blockRegExp.source, "mg");
	var match = firstMatch;

	while(match) {
		var marker = identifyMarker(match[0], registry);
		if(!marker || marker.kind !== "list-item" || !registry.isActive(marker.open)) { break; }

		var indentText = (/^[ \t]*/.exec(match[0]) || [""])[0];
		var indent = indentText.replace(/\t/g, repeatSpace(marker.indentUnit)).length;
		var level = Math.floor(indent / marker.indentUnit);
		if(level > stack.length) { level = stack.length; }

		while(stack.length > level + 1) { stack.pop(); }

		if(stack.length === level + 1 && stack[level].container !== marker.container) {
			stack.pop();
		}

		if(stack.length === level) {
			var newList = {type: "element", tag: marker.container, children: []};
			if(level === 0) {
				roots.push(newList);
			} else {
				var parentList = stack[level - 1].listNode;
				var parentItem = parentList.children[parentList.children.length - 1];
				parentItem.children.push(newList);
			}
			stack.push({listNode: newList, container: marker.container, level: level});
		}

		parser.pos = match.index + match[0].length;
		var bodyTree = parser.parseInlineRun(/(\r?\n)/mg, {eatTerminator: true});

		stack[level].listNode.children.push({
			type: "element",
			tag: marker.itemElement,
			children: bodyTree
		});

		sharedRe.lastIndex = parser.pos;
		var nextMatch = sharedRe.exec(parser.source);
		if(!nextMatch || nextMatch.index !== parser.pos) { break; }
		match = nextMatch;
	}

	return roots;
}

function repeatSpace(n) {
	var s = "";
	for(var i = 0; i < n; i++) { s += " "; }
	return s;
}

// Hr marker: emit a single childless element (default `<hr>`) for a
// thematic-break line that already matched the engine's block regex.
// No body to parse, no symbol/class chain after the open, no quoted
// args — just the classes from the marker config plus the universal
// `wltc` hook.
function parseHr(parser, marker, matchRegExp) {
	parser.pos = matchRegExp.lastIndex;
	var classes = [];
	if(marker.classes) {
		$tw.utils.each(marker.classes.split("."), function(c) {
			if(c) { classes.push(c); }
		});
	}
	classes.push("wltc");
	return [{
		type: "element",
		tag: marker.element || "hr",
		attributes: {
			"class": {type: "string", value: classes.join(" ").trim()}
		}
	}];
}

// Fenced block: capture the body between the open fence (already matched
// by the block regex) and the next matching close fence on its own line,
// with implicit close at EOF when none is found. The marker's `open`
// field pins the fence character (`open.charAt(0)`) and the MINIMUM run
// length (`open.length`); the actual open run can be longer, and the
// close must match >= that actual length. Body is captured verbatim
// (no inline parsing). The info string — text after the opening fence
// on the same line — is wired to the configured attribute (typically
// `class` with the `language-` prefix, mirroring CommonMark's output).
function parseFenced(parser, marker, match) {
	var source = parser.source;
	var openLine = match[0];
	var fenceChar = marker.open.charAt(0);

	// Count the actual fence-run length in this open instance (the marker's
	// `open.length` is the minimum; an author can use a longer run so the
	// body itself can contain shorter runs of the fence char without
	// terminating early).
	var fenceLen = 0;
	while(fenceLen < openLine.length && openLine.charAt(fenceLen) === fenceChar) {
		fenceLen++;
	}

	// Info string is everything after the fence run on the open line,
	// trimmed of surrounding whitespace.
	var infoString = openLine.substring(fenceLen).replace(/^[ \t]+|[ \t]+$/g, "");

	// Advance past the open line + its newline (CR+LF or LF). The block
	// regex captured up to (but not including) the line break so we step
	// past it explicitly.
	var afterOpen = match.index + openLine.length;
	if(source.charAt(afterOpen) === "\r") { afterOpen++; }
	if(source.charAt(afterOpen) === "\n") { afterOpen++; }

	// Scan for the matching close fence: same fence char, run length
	// >= the open run, at line start (col 0), followed by optional
	// trailing whitespace and the line terminator (or EOF).
	var fenceCharEsc = $tw.utils.escapeRegExp(fenceChar);
	var closeRe = new RegExp("^" + fenceCharEsc + "{" + fenceLen + ",}[ \\t]*(?:\\r?\\n|$)", "mg");
	closeRe.lastIndex = afterOpen;
	var closeMatch = closeRe.exec(source);
	var bodyEnd, advanceTo;
	if(closeMatch) {
		bodyEnd = closeMatch.index;
		advanceTo = closeMatch.index + closeMatch[0].length;
	} else {
		// CommonMark: missing close fence is implicitly closed at EOF.
		bodyEnd = source.length;
		advanceTo = source.length;
	}

	// Body runs from one past the open line's \n through to the start of
	// the close fence. That range includes the \n that ends the last body
	// line — keeping it would emit a visible trailing blank line inside
	// `<pre><code>...</code></pre>`. TW core's `codeblock` rule strips it
	// (the close-fence sentinel matches the \n BEFORE the fence, not the
	// fence itself); match that convention.
	var body = source.substring(afterOpen, bodyEnd).replace(/\r?\n$/, "");
	parser.pos = advanceTo;

	return buildFencedNodes(marker, infoString, body);
}

function buildFencedNodes(marker, infoString, body) {
	// Info-string value: first word by default (CommonMark / GFM
	// convention), or full string when `info-words: all`. The
	// `info-prefix` is prepended (CommonMark uses `language-`).
	var infoValue = "";
	if(infoString && marker.infoAttribute) {
		infoValue = (marker.infoWords === "all") ? infoString : infoString.split(/\s+/)[0];
		if(marker.infoPrefix) {
			infoValue = marker.infoPrefix + infoValue;
		}
	}

	// Marker identity classes (`wltc` + the marker's `.classes` chain) go
	// on the OUTERMOST block element: the wrapper when one is configured,
	// else the single element. The universal `.wltc` hook usually carries
	// a vocab-wide margin; placing it on the wrapper means the margin
	// lands OUTSIDE the visible block (e.g. above/below `<pre>`) rather
	// than inside it (where it would show as whitespace before/after the
	// rendered content). The inner element keeps only the info attribute
	// — CommonMark's `<pre><code class="language-X">...</code></pre>`
	// shape, where syntax highlighters (Prism, highlight.js, Shiki) look
	// for `.language-X` on `<code>` specifically.
	var baseClasses = [];
	if(marker.classes) {
		$tw.utils.each(marker.classes.split("."), function(c) {
			if(c) { baseClasses.push(c); }
		});
	}
	baseClasses.push("wltc");

	var hasWrapper = !!marker.wrapperElement;
	var innerAttrs = {};
	var outerAttrs = {};

	// Static attributes from the marker tiddler's `attributes` JSON field
	// land on the inner element — they describe the content element, not
	// the wrapper.
	if(marker.attributes) {
		for(var key in marker.attributes) {
			if(key !== "class") {
				innerAttrs[key] = toAttrNode(marker.attributes[key]);
			}
		}
	}

	if(hasWrapper) {
		// Wrapper carries the marker identity. Info attribute placement
		// depends on its type:
		// - `class`: stays on the INNER element alone (CommonMark
		//   `<code class="language-X">` convention — syntax highlighters
		//   like Prism / highlight.js / Shiki look there).
		// - anything else (`data-caption`, `data-attrs`, ...): goes on
		//   the OUTER wrapper alongside the marker identity classes, so
		//   a CSS rule like `.wltc-captioned-code[data-caption]::before
		//   { content: attr(data-caption); }` can target the same element
		//   for both the class hook and the attr value.
		outerAttrs["class"] = {type: "string", value: baseClasses.join(" ").trim()};
		if(infoValue) {
			if(marker.infoAttribute === "class") {
				innerAttrs["class"] = {type: "string", value: infoValue};
			} else {
				outerAttrs[marker.infoAttribute] = {type: "string", value: infoValue};
			}
		}
		parseInfoAttrsInto(marker, infoString, infoValue, outerAttrs);
	} else {
		// No wrapper — the single element collects everything.
		var innerClasses = baseClasses.slice();
		if(infoValue) {
			if(marker.infoAttribute === "class") {
				innerClasses.push(infoValue);
			} else {
				innerAttrs[marker.infoAttribute] = {type: "string", value: infoValue};
			}
		}
		innerAttrs["class"] = {type: "string", value: innerClasses.join(" ").trim()};
		parseInfoAttrsInto(marker, infoString, infoValue, innerAttrs);
	}

	var inner = {
		type: "element",
		tag: marker.element || "code",
		attributes: innerAttrs,
		children: [{type: "text", text: body}]
	};

	if(hasWrapper) {
		return [{
			type: "element",
			tag: marker.wrapperElement,
			attributes: outerAttrs,
			children: [inner]
		}];
	}
	return [inner];
}

// When `info-attrs: yes`, parse the info string (or its after-first-word
// remainder when an `info-attribute` already claimed the first word) as a
// sequence of TW macro-parameter attributes. Each parsed name is prepended
// with `data-` and the resulting attribute is added to `target`.
//
// `parseMacroParameterAsAttribute` is the canonical TW parser for the
// `name=value`, `name:value`, `name="quoted"`, `name={{!!field}}`,
// `name={{{filter}}}`, `name=<<macro>>`, `name=` ``` `subst` ``` syntaxes. Reusing it
// means all the canonical attribute value types work, plus the same
// quoting / escaping rules as everywhere else in TW.
//
// The hardcoded `data-` prefix is the security boundary: a user-supplied
// `onclick="alert(1)"` is emitted as `data-onclick="alert(1)"` (an inert
// data attribute), and a `href="javascript:..."` lands as `data-href=...`
// (no URL evaluation). No need to maintain a denylist — every parsed
// attribute becomes a data-* by construction.
function parseInfoAttrsInto(marker, infoString, infoValue, target) {
	if(!marker.infoAttrs || !infoString) { return; }
	// Determine which slice of the info string is the attr source.
	// When info-attribute already claimed the first word, parse only the
	// remainder. Otherwise the whole info string is fair game.
	var source = infoString;
	if(marker.infoAttribute && infoValue && marker.infoWords !== "all") {
		var firstWord = infoString.split(/\s+/)[0];
		source = infoString.substring(firstWord.length).replace(/^\s+/, "");
	}
	var pos = 0;
	while(pos < source.length) {
		var attr = $tw.utils.parseMacroParameterAsAttribute(source, pos);
		if(!attr || typeof attr.end !== "number" || attr.end <= pos) { break; }
		pos = attr.end;
		if(!attr.name) { continue; }
		target["data-" + attr.name] = parsedAttrToNode(attr);
	}
}

function parsedAttrToNode(attr) {
	switch(attr.type) {
		case "indirect":
			return {type: "indirect", textReference: attr.textReference};
		case "filtered":
			return {type: "filtered", filter: attr.filter};
		case "substituted":
			return {type: "substituted", rawValue: attr.rawValue};
		case "macro":
			return {type: "macro", value: attr.value};
		case "string":
		default:
			return {type: "string", value: attr.value !== undefined ? String(attr.value) : ""};
	}
}

function parseMatchTail(matchText, marker) {
	var result = {level: 1, symbol: "", classes: [], quotedArgs: []};
	var pos = marker.open.length;
	if(marker.kind === "glyph-level") {
		while(matchText.substr(pos, marker.open.length) === marker.open) {
			result.level++;
			pos += marker.open.length;
		}
	}
	if((marker.kind === "glyph" || marker.kind === "glyph-level") && marker.allowSymbol) {
		var symMatch = /^[^.:\s]*/.exec(matchText.substr(pos));
		if(symMatch && symMatch[0].length > 0) {
			result.symbol = symMatch[0];
			pos += symMatch[0].length;
		}
	}
	while(matchText.charAt(pos) === ".") {
		var cMatch = /^\.([^.\s:]+)/.exec(matchText.substr(pos));
		if(cMatch) {
			result.classes.push(cMatch[1]);
			pos += cMatch[0].length;
		} else {
			break;
		}
	}
	while(matchText.charAt(pos) === ":" && matchText.charAt(pos + 1) === '"') {
		var qMatch = /^:"([^"]*)"/.exec(matchText.substr(pos));
		if(qMatch) {
			result.quotedArgs.push(qMatch[1]);
			pos += qMatch[0].length;
		} else {
			break;
		}
	}
	return result;
}

function resolveConfig(marker, symbol, classes, level) {
	var config = {
		marker: marker,
		symbol: symbol,
		level: level,
		mode: marker.mode,
		// Block-position fires (this rule) always wrap in a block element.
		// `mode: inline` controls how the body is parsed (single line vs
		// multi-block); it doesn't change the container element type.
		element: marker.element || "div",
		endString: marker.endString,
		classes: marker.classes || "",
		attributes: marker.attributes || {},
		srcName: marker.srcName,
		userClasses: classes,
		// Marker-tiddler `debug` / `debug-string` fields. Symbol resolution
		// (applySymbolToConfig) can still override these with `_use` / legacy
		// `_debug` values from a pragma symbol.
		debug: marker.debug || "",
		debugString: marker.debugString || ""
	};
	var sym = lookupSymbol(marker, symbol);
	if(sym) {
		// Follow `_use` / `_useGlobal` aliases. Errors are surfaced via
		// the debug-codeblock path in parse().
		sym = followUse(marker, sym);
		applySymbolToConfig(config, sym);
	} else if(symbol && marker.allowSymbol) {
		// HTML-element fallback: any HTML element name overrides the default
		var cmInline = ($tw.config.cmInlineElements || []).indexOf(symbol) !== -1;
		var cmBlock = ($tw.config.cmBlockElements || []).indexOf(symbol) !== -1;
		if(cmBlock || cmInline) {
			config.element = symbol;
			if(cmBlock) { config.mode = "block"; }
		}
	}
	return config;
}

function lookupSymbol(marker, symbol) {
	if(marker.symbols && marker.symbols[symbol]) { return marker.symbols[symbol]; }
	if(marker.globalSymbols && marker.globalSymbols[symbol]) { return marker.globalSymbols[symbol]; }
	return null;
}

// Resolve `_use` (local-only alias) and `_useGlobal` (global-only alias)
// chains. v0.x semantics:
//   _use: extend target with the local pragma's overrides (local wins).
//   _useGlobal: switch to target wholesale; only the local `_debug` value
//     wins (forceDebug). Target's `_debugString` is shown so the debug
//     output reveals what config is actually applied.
function followUse(marker, sym) {
	if(sym.use) {
		var localTarget = marker.symbols && marker.symbols[sym.use];
		if(localTarget) {
			return mergeSymbol(localTarget, sym, "use");
		}
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - \\custom " + (marker.legacyKind || marker.open) + "=" + sym.use + " is not defined!"
		});
	}
	if(sym.useGlobal) {
		var globalTarget = marker.globalSymbols && marker.globalSymbols[sym.useGlobal];
		if(globalTarget) {
			var merged = $tw.utils.extend({}, globalTarget);
			delete merged.useGlobal;
			// Local `_debug` wins (v0.x's forceDebug capture).
			if(sym.debug) { merged.debug = sym.debug; }
			return merged;
		}
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - global \\custom " + (marker.legacyKind || marker.open) + "=" + sym.useGlobal + " is not defined!"
		});
	}
	return sym;
}

// Merge target onto sym (sym's overrides win), dropping the `use` / `useGlobal`
// field so we don't re-follow on a subsequent resolveConfig pass.
function mergeSymbol(target, sym, useField) {
	var merged = $tw.utils.extend({}, target, sym);
	delete merged[useField];
	// Attributes from both sides should compose, not overwrite.
	if(target.attributes && sym.attributes) {
		merged.attributes = $tw.utils.extend({}, target.attributes, sym.attributes);
	}
	return merged;
}

function applySymbolToConfig(config, sym) {
	if(sym.element) { config.element = sym.element; }
	if(sym.endString !== undefined) { config.endString = sym.endString; }
	if(sym.classes) { config.classes = config.classes + sym.classes; }
	if(sym.mode) { config.mode = sym.mode; }
	if(sym.srcName) { config.srcName = sym.srcName; }
	if(sym.attributes) { config.attributes = $tw.utils.extend({}, config.attributes, sym.attributes); }
	if(sym.params) { config.params = sym.params; }
	if(sym.debug) { config.debug = sym.debug; }
	if(sym.debugString) { config.debugString = sym.debugString; }
}

// paragraph-marker: explicit schema flag. "yes" opts into paragraph
// terminator (blank line); anything else is non-paragraph (single newline).
function isParagraphMarker(marker) {
	return !!marker && marker.paragraphMarker === "yes";
}

function parseBody(parser, config) {
	if(config.mode === "block") {
		// Explicit endString wins regardless of wrapper element. Browser
		// auto-closes `<p>` when block children appear inside, matching
		// v0.x's parseBlocks-with-newline-terminator behaviour.
		if(config.endString) {
			return parser.parseBlocks($tw.utils.escapeRegExp(unescapeEndString(config.endString)));
		}
		// `<p>` wrapper without explicit endString: parse body inline so the
		// paragraph wrapper doesn't nest an inner paragraph. This is a DOM
		// constraint on the rendered element, not the marker's paragraph-ness.
		if(config.element === "p") {
			return parser.parseInlineRun(/(\r?\n\r?\n)/mg, {eatTerminator: true});
		}
		// Non-paragraph markers (´, °, › and any marker with paragraph-marker:no
		// or undefined+element!=p) default to single-newline terminator so each
		// fire on its own line is a separate node. Paragraph markers fall through
		// to blank-line default.
		if(config.marker && !isParagraphMarker(config.marker)) {
			return parser.parseBlock("\\r?\\n");
		}
		return parser.parseBlock();
	}
	// mode === "inline": pick terminator by marker's paragraph-ness. v0.x's
	// useParagraph markers (», ≈, ¶) terminate at a blank line; the rest (´, °, ›)
	// terminate at single newline. The paragraph-marker field is the canonical
	// signal; element===p is the back-compat fallback.
	var terminator;
	if(config.endString) {
		terminator = new RegExp("(" + $tw.utils.escapeRegExp(unescapeEndString(config.endString)) + ")", "mg");
	} else if(config.marker && isParagraphMarker(config.marker)) {
		terminator = /(\r?\n\r?\n)/mg;
	} else {
		terminator = /(\r?\n)/mg;
	}
	return parser.parseInlineRun(terminator, {eatTerminator: true});
}

// TW's parseAttribute returns `_endString="\n"` as the literal two-char
// string `\n`. Unescape JS-style sequences so users can write `"\n"`,
// `"\r\n"`, `"\t"` and have them mean what they look like.
function unescapeEndString(s) {
	if(typeof s !== "string") { return s; }
	return s.replace(/\\([nrt\\'"])/g, function(_, c) {
		switch(c) {
			case "n": return "\n";
			case "r": return "\r";
			case "t": return "\t";
			case "\\": return "\\";
			case "'": return "'";
			case '"': return '"';
		}
		return c;
	});
}

function buildNode(config, children, source, contentStart, parserPos) {
	var classes = [];
	if(config.classes) {
		$tw.utils.each(config.classes.split("."), function(c) {
			if(c) { classes.push(c); }
		});
	}
	if(config.userClasses && config.userClasses.length) {
		classes = classes.concat(config.userClasses);
	}
	if(config.level && config.marker && config.marker.kind === "glyph-level") {
		classes.push("wltc-l" + config.level);
	}
	classes.push("wltc");
	var attrs = {
		"class": {type: "string", value: classes.join(" ").trim()}
	};
	if(config.attributes) {
		for(var key in config.attributes) {
			if(key !== "class") {
				attrs[key] = toAttrNode(config.attributes[key]);
			}
		}
	}
	if(config.params && config.params.length > 0) {
		var args = config.quotedArgs || [];
		for(var i = 0; i < config.params.length; i++) {
			var p = config.params[i];
			if(!p || !p.name) { continue; }
			var override = args[i];
			if(typeof override === "string" && override.length > 0) {
				attrs[p.name] = {type: "string", value: override};
			} else {
				attrs[p.name] = toAttrNode(p);
			}
		}
	}
	if(config.element.charAt(0) === "$") {
		var contentEnd = parserPos;
		if(config.endString) { contentEnd -= config.endString.length; }
		var innerText = source.substring(contentStart, contentEnd);
		// Strip trailing line-endings consumed by the implicit terminator
		// (eatTerminator on inline mode, or the blank-line terminator on
		// block-with-paragraph wrapping). Otherwise widget attributes pick
		// up stray "\n" — which becomes "%0A" in URL-valued attrs.
		if(!config.endString) {
			innerText = innerText.replace(/(?:\r?\n)+$/, "");
		}
		attrs[config.srcName || "src"] = {type: "string", value: innerText};
		return {
			type: config.element.substr(1),
			tag: config.element,
			attributes: attrs,
			children: children
		};
	}
	return {
		type: "element",
		tag: config.element,
		attributes: attrs,
		children: children
	};
}

// Convert a parseAttribute token (or a plain string) into a parse-tree
// attribute node. Preserves indirect / macro / filtered / substituted
// types so `{{!!field}}`, `<<macro>>`, and `{{{filter}}}` survive into
// the rendered widget instead of being stringified to "[object Object]".
function toAttrNode(token) {
	if(token === null || token === undefined) {
		return {type: "string", value: ""};
	}
	if(typeof token === "string") {
		return {type: "string", value: token};
	}
	switch(token.type) {
		case "indirect":
			return {type: "indirect", textReference: token.textReference};
		case "macro":
			return {type: "macro", value: token.value};
		case "filtered":
			return {type: "filtered", filter: token.filter};
		case "substituted":
			return {type: "substituted", rawValue: token.rawValue};
		case "string":
		default:
			return {type: "string", value: (token.value !== undefined) ? String(token.value) : ""};
	}
}
