			});
			_globalSymbolsCache = snapshot;
			_globalSymbolsAtChange = ptChange;
		}
	} finally {
		CmRegistry._loadingGlobals = false;
	}
};

// Attach a cached global-symbols map (open → symbol table) onto this
// registry's marker configs as `globalSymbols`. Used by both the
// memoized cache-hit path and any other consumer that already has the
// extracted map.
CmRegistry.prototype.applyGlobalSymbols = function(symbolsByOpen) {
	var self = this;
	Object.keys(symbolsByOpen).forEach(function(open) {
		var lM = self.markers[open];
		if(lM) { lM.globalSymbols = symbolsByOpen[open]; }
	});
};

CmRegistry.prototype.findByOpen = function(literal) {
	return this.markers[literal] || null;
};

// Look up a marker by its open literal, or by its legacy-kind name (tick,
// degree, etc.). Used by the \custom pragma so legacy `degree=foo` syntax
// keeps resolving after the kind-name layer was retired.
CmRegistry.prototype.findByOpenOrLegacyKind = function(name) {
	if(this.markers[name]) { return this.markers[name]; }
	for(var key in this.markers) {
		if(this.markers[key].legacyKind === name) {
			return this.markers[key];
		}
	}
	return null;
};

CmRegistry.prototype.list = function(predicate) {
	var out = [];
	for(var key in this.markers) {
		if(!predicate || predicate(this.markers[key])) {
			out.push(this.markers[key]);
		}
	}
	return out;
};

CmRegistry.prototype.getBlockRegex = function() {
	if(this.dirty || !this.blockRegex) { this.rebuildRegexes(); }
	return this.blockRegex;
};

CmRegistry.prototype.getInlineRegex = function() {
	if(this.dirty || !this.inlineRegex) { this.rebuildRegexes(); }
	return this.inlineRegex;
};

CmRegistry.prototype.rebuildRegexes = function() {
	var blockMarkers = this.list(function(m) {
		return m.kind === "glyph" || m.kind === "glyph-level" || m.kind === "word" || m.kind === "list-item" || m.kind === "fenced" || m.kind === "hr";
	});
	// Inline markers come from the parallel `inlineMarkers` dict, not from
	// filtering `this.markers` — that flat dict gets clobbered when an
	// inline-kind marker shares an `open` with a block-kind one (markdown's
	// ITALIC `*` vs ITEM-STAR `*` is the canonical case). The dict is
	// bucketed (array per open) so two inline-kind markers can share an
	// open too — e.g. LINK `[text](url)` and LINK-REF `[text][label]`.
	var inlineMarkers = [];
	var openKeys = Object.keys(this.inlineMarkers);
	for(var k = 0; k < openKeys.length; k++) {
		var bucket = this.inlineMarkers[openKeys[k]];
		for(var j = 0; j < bucket.length; j++) {
			inlineMarkers.push(bucket[j]);
		}
	}

	// Word arms longest-first so longer literals preempt shorter prefixes
	blockMarkers.sort(function(a, b) {
		if(a.kind === "word" && b.kind === "word") {
			return b.open.length - a.open.length;
		}
		return 0;
	});

	// Inline arms longest-first for the same reason (`***` must win over
	// `**` must win over `*`; JS regex alternation picks the first arm
	// that matches at a position).
	inlineMarkers.sort(function(a, b) {
		return b.open.length - a.open.length;
	});

	var blockArms = [];
	$tw.utils.each(blockMarkers, function(m) {
		blockArms.push(buildBlockArm(m));
	});
	var inlineArms = [];
	$tw.utils.each(inlineMarkers, function(m) {
		// Cache the built arm on the marker config so
		// `identifyInlinePairMarker` can regex-test the matchText against
		// each candidate in a same-`open` bucket without rebuilding.
		if(!m.cachedInlineArm) { m.cachedInlineArm = buildInlineArm(m); }
		inlineArms.push(m.cachedInlineArm);
	});

	this.blockRegex = blockArms.length ? new RegExp(blockArms.join("|"), "mg") : null;
	this.inlineRegex = inlineArms.length ? new RegExp(inlineArms.join("|"), "mg") : null;
	this.dirty = false;
};

// Build a case-folded regex pattern for a literal: each letter becomes
// `[Aa]`, non-letters are escaped. Used by case-insensitive word markers
// so the combined block regex can mix case-sensitive and case-insensitive
// arms without per-arm regex flags.
function caseFoldPattern(s) {
	var out = "";
	for(var i = 0; i < s.length; i++) {
		var c = s.charAt(i);
		var lc = c.toLowerCase();
		var uc = c.toUpperCase();
		if(lc !== uc) {
			out += "[" + uc + lc + "]";
		} else {
			out += $tw.utils.escapeRegExp(c);
		}
	}
	return out;
}

function buildBlockArm(m) {
	var open = $tw.utils.escapeRegExp(m.open);
	// Strict-class rule kicks in when allow-symbol is off (e.g. dot marker)
	// to keep prose like ".NET" / ".com" from matching.
	var classChain = m.allowSymbol
		? String.raw`(?:\.[^.\r\n\s:]+)*`
		: String.raw`(?:\.[a-z][\w-]*)*`;
	var symbol = m.allowSymbol ? String.raw`(?:[^.:\r\n\s]+)?` : "";
	// Positional quoted-argument chain (`:"a":"b":"c"`), feeds the
	// pragma's `_params` positional overrides at fire time.
	var quotedArgs = String.raw`(?::"[^"]*")*`;
	var bound = String.raw`(?=[ \t\r\n]|$)`;

	// no-space-bound: compact form for spec-compliant interop (e.g. Fountain
	// `.SCENE`, `@NAME`). Skips symbol/class/quoted-arg capture and replaces
	// the whitespace bound with a negative lookahead against the open itself,
	// so `..` / `##` don't false-match while `.S` / `#H` do.
	if(m.noSpaceBound && (m.kind === "glyph" || m.kind === "glyph-level")) {
		var notOpen = "(?!" + open + ")";
		if(m.kind === "glyph") {
			return `(?:${open}${notOpen})`;
		}
		var lvlCompact = `(?:${open}){1,${m.maxLevel}}`;
		return `(?:${lvlCompact}${notOpen})`;
	}

	switch(m.kind) {
		case "glyph":
			return `(?:${open}${symbol}${classChain}${quotedArgs}${bound})`;
		case "glyph-level":
			var lvl = `(?:${open}){1,${m.maxLevel}}`;
			return `(?:${lvl}${symbol}${classChain}${quotedArgs}${bound})`;
		case "word":
			var wordOpen = m.caseInsensitive ? caseFoldPattern(m.open) : open;
			var wordCls = m.allowClasses ? classChain : "";
			if(m.trailingBlank) {
				// Spec-correct: body extends to end-of-line, then a blank
				// line OR end-of-input must follow. Without this, scene
				// headings (`INT. KITCHEN`) followed immediately by an
				// uppercase line would compete with the auto-character
				// rule (Fountain disambiguates on the trailing blank).
				var trail = String.raw`(?=[^\n]*(?:\n(?:\n|(?![\s\S]))|(?![\s\S])))`;
				return `(?:${wordOpen}${wordCls}${bound}${trail})`;
			}
			return `(?:${wordOpen}${wordCls}${bound})`;
		case "list-item":
			// Match line-start + optional indent + bullet + required space.
			// Bullet is either the openPattern regex (for OL: \d+\.) or the
			// escaped open literal (for UL: - / * / +).
			var bullet = m.openPattern || open;
			return `(?:^[ \\t]*(?:${bullet})[ \\t]+)`;
		case "hr":
			// CommonMark thematic break shape: 0-3 spaces of indent, then
			// the marker's literal `open` (e.g. `---`, `***`, `___`), then
			// any number of additional repetitions of the first char with
			// optional inner whitespace, then optional trailing whitespace
			// and EOL/EOF. The literal-3-char open avoids the same-`open`
			// collision a single-char design would have with list-item
			// markers (ITEM-DASH `open: -`, ITEM-STAR `open: *`).
			var hrOpenLit = $tw.utils.escapeRegExp(m.open);
			var hrChar = $tw.utils.escapeRegExp(m.open.charAt(0));
			return String.raw`(?:^[ \t]{0,3}${hrOpenLit}(?:[ \t]*${hrChar})*[ \t]*(?:\r?\n|$))`;
		case "fenced":
			// Match line-start + a fence run of N>=open.length chars (where
			// the fence char is open.charAt(0)) + any info-string content
			// to end of line. Backticks (or whatever the fence char is) are
			// disallowed in the info string so an inline code-span open on
			// the same line can't be false-matched as a block fence
			// (CommonMark constraint). Close + body are handled by
			// parseFenced; only the open line is captured here.
			var fenceChar = $tw.utils.escapeRegExp(m.open.charAt(0));
			var minLen = m.open.length;
			return String.raw`(?:^${fenceChar}{${minLen},}[^${fenceChar}\r\n]*$)`;
		default:
			return `(?:${open}${bound})`;
	}
}

function buildInlineArm(m) {
	if(m.kind === "linked-pair") {
		return buildLinkedPairArm(m);
	}
	if(m.kind === "autolink") {
		return buildAutolinkArm(m);
	}
	var open = $tw.utils.escapeRegExp(m.open);
	var quotedArgs = String.raw`(?::"[^"]*")*`;
	// open-variable: match a MAXIMAL run of the open character, flanked
	// by non-open chars on both sides (start-of-input / end-of-input
	// count as non-open via the JS regex anchor semantics). parse()
	// then walks forward to find a same-length closing run with the
	// same flanking property. Single-char open assumed — multi-char
	// "open" repetition isn't useful for the CommonMark code-span case
	// this covers.
	if(m.openVariable) {
		return String.raw`(?<!${open})${open}+(?!${open})`;
	}
	// allow-symbol: no skips the symbol + class chain. Required for
	// body-only markers like Fountain's `*italic*` where there's no symbol
	// to capture between open and body; the default arm would eat "italic"
	// as the symbol and leave body empty.
	if(m.allowSymbol === false) {
		return String.raw`(?:${open}${quotedArgs})`;
	}
	// Symbol/class char-class must exclude the first char of the close marker,
	// otherwise text like `{!body!}` swallows the `!}` close into the symbol.
	var closeFirst = m.close ? $tw.utils.escapeRegExp(m.close.charAt(0)) : "";
	return String.raw`(?:${open}(?:[^.:\r\n\s${closeFirst}]+)?(?:\.[^.\r\n\s:${closeFirst}]+)*${quotedArgs})`;
}

// Linked-pair arm: open BODY close link-open LINK link-close. Body and
// link runs use lazy first-char-of-closer exclusion classes so they can't
// run past the close literal. Multi-char closes work because the first
// char is the discriminator (CommonMark `]` / `)` are single-char anyway).
// `findNextMatch` only fires when the WHOLE pattern matches, so a bare
// `[` with no following `](url)` falls through to plain text — no
// post-hoc fallback needed in parse().
function buildLinkedPairArm(m) {
	var open = $tw.utils.escapeRegExp(m.open);
	var close = $tw.utils.escapeRegExp(m.close);
	var linkOpen = $tw.utils.escapeRegExp(m.linkOpen || "(");
	var linkClose = $tw.utils.escapeRegExp(m.linkClose || ")");
	var closeFirstEsc = $tw.utils.escapeRegExp((m.close || "]").charAt(0));
	var linkCloseFirstEsc = $tw.utils.escapeRegExp((m.linkClose || ")").charAt(0));
	var bodyClass = String.raw`[^${closeFirstEsc}\r\n]`;
	var linkClass = String.raw`[^${linkCloseFirstEsc}\r\n]`;
	return String.raw`(?:${open}${bodyClass}*?${close}${linkOpen}${linkClass}*?${linkClose})`;
}

// Autolink arm: open BODY close with body content excluding whitespace,
// the open's first char, and the close's first char. CommonMark autolinks
// use `<` / `>`, so the default is `<[^\s<>]+>`. The body is captured raw
// and validated against the marker's `url-pattern` / `email-pattern` in
// parseAutolink (the regex here is permissive; pattern enforcement is
// done post-match so a non-matching `<text>` falls through to literal).
function buildAutolinkArm(m) {
	var open = $tw.utils.escapeRegExp(m.open);
	var close = $tw.utils.escapeRegExp(m.close);
	var openFirst = $tw.utils.escapeRegExp(m.open.charAt(0));
	var closeFirst = $tw.utils.escapeRegExp(m.close.charAt(0));
	return String.raw`(?:${open}[^\s${openFirst}${closeFirst}]+${close})`;
}

CmRegistry.ensurePageTemplateDedupe = ensurePageTemplateDedupe;

// CommonMark reference-link label normalisation: case-insensitive,
// whitespace-collapsed, leading/trailing trimmed. Used by both the
// `markdown-ref-def` wikirule (storing) and `parseLinkedPair` (looking
// up) so `[Click Me]` and `[click me]` and `[  click  me  ]` all
// resolve to the same key `click me` in `parser.cmRegistry.linkRefs`.
CmRegistry.normalizeRefLabel = function(label) {
	if(typeof label !== "string") { return ""; }
	return label.replace(/\s+/g, " ").trim().toLowerCase();
};

// Static helper called from wikirule init(): builds a CmRegistry on the
// parser if absent, loads all markers + global pragmas, activates the
// vocabs declared by `;vocab=` in the parser type, and schedules the
// deferred amend-rules pass. Idempotent — rules sharing a parser only
// pay the cost on the first call. Returns the parser's registry so
// callers needing it (cmblock/cminline for getBlockRegex/getInlineRegex)
// don't re-read `parser.cmRegistry`.
CmRegistry.ensureRegistry = function(parser) {
	if(parser.cmRegistry) { return parser.cmRegistry; }
	parser.cmRegistry = new CmRegistry(parser.wiki);
	parser.cmRegistry.loadAllMarkers();
	parser.cmRegistry.loadGlobalPragmas();
	parser.cmRegistry.activateFromTypeField(parser.type);
	parser.cmRegistry.applyAmendRules(parser);
	return parser.cmRegistry;
};

exports.CmRegistry = CmRegistry;
exports.CM_MARKER_TAG = MARKER_TAG;
exports.CM_VOCAB_TAG = VOCAB_TAG;
","type":"application/javascript","module-type":"utils"},"$:/plugins/wikilabs/custom-markup/yaml.js":{"title":"$:/plugins/wikilabs/custom-markup/yaml.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/yaml.js
type: application/javascript
module-type: library

Minimal YAML parser for frontmatter extraction.
API-compatible subset of js-yaml: load(string) → object, dump(object) → string.
Handles scalars, flow/block arrays, and simple nested maps.

Vendored from Jermolene's TiddlyWiki5 PR #9806 (`bidirectional-filesystem`
branch), originally `$:/plugins/tiddlywiki/markdown/yaml.js`. Title
adjusted to this plugin's namespace; contents otherwise unchanged.

\*/
"use strict";

function YAMLException(message, mark) {
	this.name = "YAMLException";
	this.message = message;
	this.mark = mark || null;
}
YAMLException.prototype = Object.create(Error.prototype);
YAMLException.prototype.constructor = YAMLException;

// -- Scalar parsing --

function parseScalar(raw) {
	if(raw === "" || raw === "null" || raw === "Null" || raw === "NULL" || raw === "~") {
		return null;
	}
	if(raw === "true" || raw === "True" || raw === "TRUE") {
		return true;
	}
	if(raw === "false" || raw === "False" || raw === "FALSE") {
		return false;
	}
	// Quoted strings
	if((raw[0] === '"' && raw[raw.length - 1] === '"') ||
	   (raw[0] === "'" && raw[raw.length - 1] === "'")) {
		var inner = raw.slice(1, -1);
		if(raw[0] === '"') {
			// Handle basic escape sequences in double-quoted strings.
			// Use a single pass so each escape consumes its backslash before
			// later replacements can re-interpret it (e.g. "\\n" must become
			// backslash + n, not backslash + newline).
			inner = inner.replace(/\\(.)/g, function(_, c) {
				switch(c) {
					case "n": return "\n";
					case "t": return "\t";
					case "r": return "\r";
					case "\\": return "\\";
					case '"': return '"';
					default: return c;
				}
			});
		}
		return inner;
	}
	// Numbers: integers and floats
	if(/^-?(?:0|[1-9]\d*)(?:\.\d+)?(?:[eE][+-]?\d+)?$/.test(raw)) {
		var num = Number(raw);
		if(!isNaN(num)) {
			return num;
		}
	}
	// Hex integers
	if(/^0x[0-9a-fA-F]+$/.test(raw)) {
		return parseInt(raw, 16);
	}
	// Octal integers
	if(/^0o[0-7]+$/.test(raw)) {
		return parseInt(raw.slice(2), 8);
	}
	// Special floats
	if(raw === ".inf" || raw === ".Inf" || raw === ".INF") {
		return Infinity;
	}
	if(raw === "-.inf" || raw === "-.Inf" || raw === "-.INF") {
		return -Infinity;
	}
	if(raw === ".nan" || raw === ".NaN" || raw === ".NAN") {
		return NaN;
	}
	return raw;
}

// -- Flow sequence parser: [item, item, ...] --

function parseFlowSequence(str) {
	// Strip outer brackets and split respecting nested brackets and quotes
	var inner = str.slice(1, -1).trim();
	if(inner === "") {
		return [];
	}
	var items = [],
		current = "",
		depth = 0,
		inSingle = false,
		inDouble = false;
	for(var i = 0; i < inner.length; i++) {
		var ch = inner[i];
		if(ch === "\\" && inDouble) {
			current += ch + (inner[i + 1] || "");
			i++;
			continue;
		}
		if(ch === '"' && !inSingle) {
			inDouble = !inDouble;
			current += ch;
			continue;
		}
		if(ch === "'" && !inDouble) {
			inSingle = !inSingle;
			current += ch;
			continue;
		}
		if(!inSingle && !inDouble) {
			if(ch === "[" || ch === "{") {
				depth++;
			} else if(ch === "]" || ch === "}") {
				depth--;
			} else if(ch === "," && depth === 0) {
				items.push(parseScalar(current.trim()));
				current = "";
				continue;
			}
		}
		current += ch;
	}
	if(current.trim() !== "") {
		items.push(parseScalar(current.trim()));
	}
	return items;
}

// -- Flow mapping parser: {key: value, ...} --

function parseFlowMapping(str) {
	var inner = str.slice(1, -1).trim();
	if(inner === "") {
		return {};
	}
	var result = Object.create(null),
		pairs = [],
		current = "",
		depth = 0,
		inSingle = false,
		inDouble = false;
	for(var i = 0; i < inner.length; i++) {
		var ch = inner[i];
		if(ch === "\\" && inDouble) {
			current += ch + (inner[i + 1] || "");
			i++;
			continue;
		}
		if(ch === '"' && !inSingle) {
			inDouble = !inDouble;
			current += ch;
			continue;
		}
		if(ch === "'" && !inDouble) {
			inSingle = !inSingle;
			current += ch;
			continue;
		}
		if(!inSingle && !inDouble) {
			if(ch === "[" || ch === "{") {
				depth++;
			} else if(ch === "]" || ch === "}") {
				depth--;
			} else if(ch === "," && depth === 0) {
				pairs.push(current.trim());
				current = "";
				continue;
			}
		}
		current += ch;
	}
	if(current.trim() !== "") {
		pairs.push(current.trim());
	}
	for(var p = 0; p < pairs.length; p++) {
		var colonIdx = pairs[p].indexOf(":");
		if(colonIdx !== -1) {
			var key = pairs[p].slice(0, colonIdx).trim(),
				val = pairs[p].slice(colonIdx + 1).trim();
			result[parseScalar(key)] = parseScalar(val);
		}
	}
	return result;
}

// -- Block parser (indentation-based) --

/*
Parse block YAML from an array of {indent, raw} line objects.
Returns the parsed value (object, array, or scalar).
*/
function parseBlock(lines, start, baseIndent) {
	if(start >= lines.length) {
		return {value: null, nextIndex: start};
	}
	var firstLine = lines[start];
	// Block sequence: lines starting with "- "
	if(firstLine.raw.indexOf("- ") === 0 || firstLine.raw === "-") {
		return parseBlockSequence(lines, start, firstLine.indent);
	}
	// Block mapping: lines containing ":"
	if(firstLine.raw.indexOf(":") !== -1) {
		return parseBlockMapping(lines, start, firstLine.indent);
	}
	// Bare scalar
	return {value: parseScalar(firstLine.raw), nextIndex: start + 1};
}

function parseBlockSequence(lines, start, seqIndent) {
	var result = [],
		i = start;
	while(i < lines.length && lines[i].indent === seqIndent && (lines[i].raw.indexOf("- ") === 0 || lines[i].raw === "-")) {
		var itemRaw = lines[i].raw.slice(2); // After "- "
		// Check for inline flow value
		var trimmed = itemRaw.trim();
		if(trimmed[0] === "[") {
			result.push(parseFlowSequence(trimmed));
			i++;
		} else if(trimmed[0] === "{") {
			result.push(parseFlowMapping(trimmed));
			i++;
		} else if(trimmed === "" || trimmed === undefined) {
			// Multi-line block item — collect indented children
			i++;
			var childLines = [];
			while(i < lines.length && lines[i].indent > seqIndent) {
				childLines.push(lines[i]);
				i++;
			}
			if(childLines.length > 0) {
				result.push(parseChildBlockValue(childLines));
			} else {
				result.push(null);
			}
		} else if(trimmed.indexOf(":") !== -1 && !isQuotedColonValue(trimmed)) {
			// Inline mapping start as sequence item
			// Collect this line (re-indented) plus any deeper-indented children
			var mappingLines = [{indent: seqIndent + 2, raw: trimmed}];
			i++;
			while(i < lines.length && lines[i].indent > seqIndent) {
				mappingLines.push(lines[i]);
				i++;
			}
			var parsedMap = parseBlock(mappingLines, 0, mappingLines[0].indent);
			result.push(parsedMap.value);
		} else {
			result.push(parseScalar(trimmed));
			i++;
		}
	}
	return {value: result, nextIndex: i};
}

function isQuotedColonValue(str) {
	// Check if the colon is inside quotes (meaning it's a scalar, not a mapping)
	var colonIdx = str.indexOf(":");
	if(colonIdx === -1) {
		return false;
	}
	// If the value starts with a quote and the colon is inside, it's a quoted scalar
	if((str[0] === '"' || str[0] === "'") && colonIdx > 0) {
		var quote = str[0];
		var closeIdx = str.indexOf(quote, 1);
		if(closeIdx > colonIdx) {
			return true;
		}
	}
	return false;
}

function parseBlockMapping(lines, start, mapIndent) {
	var result = Object.create(null),
		i = start;
	while(i < lines.length && lines[i].indent === mapIndent) {
		var line = lines[i].raw,
			colonIdx = line.indexOf(":");
		if(colonIdx === -1) {
			break;
		}
		var key = line.slice(0, colonIdx).trim(),
			valRaw = line.slice(colonIdx + 1).trim();
		if(valRaw !== "") {
			// Inline value
			if(valRaw[0] === "[") {
				result[key] = parseFlowSequence(valRaw);
			} else if(valRaw[0] === "{") {
				result[key] = parseFlowMapping(valRaw);
			} else {
				result[key] = parseScalar(valRaw);
			}
			i++;
		} else {
			// Block value on subsequent indented lines
			i++;
			var childLines = [];
			while(i < lines.length && lines[i].indent > mapIndent) {
				childLines.push(lines[i]);
				i++;
			}
			if(childLines.length > 0) {
				result[key] = parseChildBlockValue(childLines);
			} else {
				result[key] = null;
			}
		}
	}
	return {value: result, nextIndex: i};
}

// Decide whether collected child lines form a structured value (block
// mapping / block sequence) or a multi-line scalar (Fountain title-page
// `Notes:\n  first\n  second` convention). For the scalar case, leading
